function setLang(l, el) {
  document.querySelectorAll('.lang-pill').forEach(b => b.classList.remove('active'));
  el.classList.add('active');
  const t = LANGS[l];
  const h1 = document.querySelector('#page-home h1');
  const sub = document.querySelector('#page-home .text-lg.text-on-surface-variant');
  const inp = document.querySelector('#page-home input[placeholder="Job title or keyword"]');
  if (h1)  h1.innerHTML = t.hero;
  if (sub) sub.textContent = t.sub;
  if (inp) inp.placeholder = t.ph;
  featToast('🌐 Language changed!');
}

