  python:[{q:'Output of print(2**3)?',o:['6','8','9','None'],a:1},{q:'Keyword to define a function?',o:['function','define','def','func'],a:2},{q:'How to create a list?',o:['{}','()','[]','<>'],a:2},{q:'Method to add to a list?',o:['.add()','.push()','.append()','.insert_end()'],a:2},{q:'What does len() return?',o:['Last item','First item','Length / count','Type'],a:2}],
  design:[{q:'RGB stands for?',o:['Red Green Black','Red Green Blue','Range Gradient Border','None'],a:1},{q:'Which format supports transparency?',o:['JPEG','BMP','PNG','GIF only'],a:2},{q:'Kerning means?',o:['Font size','Space between letters','Line height','Font style'],a:1},{q:'Print design uses?',o:['RGB','HSV','CMYK','HEX'],a:2},{q:'Vector graphic is?',o:['Pixel-based','Math-based scalable','Photo format','Video'],a:1}],
